import{_ as a,o as i,c as n,a2 as e}from"./chunks/framework.BflysNKA.js";const u=JSON.parse('{"title":"协议兼容声明","description":"","frontmatter":{},"headers":[],"relativePath":"guide/openai-compatible.md","filePath":"guide/openai-compatible.md","lastUpdated":1778577020000}'),l={name:"guide/openai-compatible.md"};function p(t,s,h,r,o,d){return i(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="协议兼容声明" tabindex="-1">协议兼容声明 <a class="header-anchor" href="#协议兼容声明" aria-label="Permalink to &quot;协议兼容声明&quot;">​</a></h1><p>支持 <code>OpenAI Compatible API</code>（OpenAI 兼容接口）的工具，通常都可以通过自定义 Base URL 和 API Key 接入 小蓝中转站。</p><p>这一页主要面向：</p><ul><li>Cherry Studio</li><li>Codex</li><li>自定义脚本</li><li>OpenAI SDK</li><li>支持 <code>OPENAI_BASE_URL</code> 或同类字段的客户端</li></ul><p>这一页不适用于：</p><ul><li>Claude Code</li><li>Gemini CLI 当前版本</li></ul><p>如果你用的是 Claude Code，查看 <a href="/deploy/claude-code">Claude Code 部署</a>。<br> 如果你用的是 Gemini CLI，查看 <a href="/deploy/gemini-cli">Gemini CLI 部署</a>。</p><h2 id="唯一-endpoint" tabindex="-1">唯一 Endpoint <a class="header-anchor" href="#唯一-endpoint" aria-label="Permalink to &quot;唯一 Endpoint&quot;">​</a></h2><p>OpenAI 兼容入口统一使用：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>https://xiaolan1.cn/v1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>常见字段名可能写成：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>Base URL</span></span>
<span class="line"><span>API Base</span></span>
<span class="line"><span>Endpoint</span></span>
<span class="line"><span>OpenAI Base URL</span></span>
<span class="line"><span>OPENAI_BASE_URL</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>看到这些字段，都填 <code>https://xiaolan1.cn/v1</code>。</p><p>这里填的是 <strong>接口根地址</strong>，不是网页地址，也不是某个具体接口的完整路径。<br> 最稳的写法，就是停在 <code>/v1</code> 这一层。</p><p>不要填：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>https://xiaolan1.cn</span></span>
<span class="line"><span>https://xiaolan1.cn/dashboard/overview</span></span>
<span class="line"><span>https://xiaolan1.cn/pricing</span></span>
<span class="line"><span>https://xiaolan1.cn/v1/chat/completions</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>前面三个是网页地址，最后一个是具体接口路径，都不适合作为 Base URL。</p><p>地址填错后的常见现象：</p><ul><li>保存配置时看起来没问题，但一发请求就报错</li><li>返回网页内容，而不是 JSON</li><li>客户端提示 <code>404</code>、<code>Not Found</code> 或 endpoint 不存在</li><li>模型列表始终拉不下来</li></ul><p>遇到这类现象时，先把地址改回 <code>https://xiaolan1.cn/v1</code>，再继续查 Key 和模型名。</p><h2 id="支持的核心能力范围" tabindex="-1">支持的核心能力范围 <a class="header-anchor" href="#支持的核心能力范围" aria-label="Permalink to &quot;支持的核心能力范围&quot;">​</a></h2><p>小蓝中转站 会把多家模型能力映射到常见 OpenAI 兼容接口：</p><ul><li><strong>对话补全 (Chat Completions)</strong>：最高频的场景，支持流式输出。请参阅 <a href="/api/chat">/v1/chat/completions 规范</a>。</li><li><strong>文本补全 (Completions)</strong>：适用于代码补全工具。请参阅 <a href="/api/completions">/v1/completions 规范</a>。</li><li><strong>向量生成 (Embeddings)</strong>：适用于本地 RAG 和知识库检索。请参阅 <a href="/api/embeddings">/v1/embeddings 规范</a>。</li><li><strong>其他周边能力</strong>：请查阅左侧 API 详细参考手册。</li></ul><p>只要工具本身支持改 <code>baseURL</code>、<code>base_url</code>、<code>OPENAI_BASE_URL</code> 或同类字段，一般都能按这套方式接入。</p><h2 id="鉴权写法" tabindex="-1">鉴权写法 <a class="header-anchor" href="#鉴权写法" aria-label="Permalink to &quot;鉴权写法&quot;">​</a></h2><p>标准 Header：</p><div class="language-txt vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span>Authorization: Bearer sk-你的专属Key</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>很多桌面客户端会自动补 <code>Bearer</code>，输入框里通常只需要粘贴 Key。<br> 自己写脚本时，Header 要完整。</p><h2 id="环境变量接法" tabindex="-1">环境变量接法 <a class="header-anchor" href="#环境变量接法" aria-label="Permalink to &quot;环境变量接法&quot;">​</a></h2><p>很多 CLI 工具和脚本，除了图形界面填地址，也支持直接从环境变量读取：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> OPENAI_BASE_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;https://xiaolan1.cn/v1&quot;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;"> OPENAI_API_KEY</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;sk-你的专属Key&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>这样做的好处是地址和 Key 分开管理：</p><ul><li>改 Key 时不用回头重写脚本</li><li>多个脚本可以共用同一套环境</li><li>出问题时更容易判断是地址错了，还是 Key 错了</li></ul><p>Windows PowerShell：</p><div class="language-powershell vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">Environment</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">]::SetEnvironmentVariable(</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;OPENAI_BASE_URL&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;https://xiaolan1.cn/v1&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;User&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">[</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">Environment</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">]::SetEnvironmentVariable(</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">&quot;OPENAI_API_KEY&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;sk-你的专属Key&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#D73A49;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;User&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#24292E;">)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="最小验证" tabindex="-1">最小验证 <a class="header-anchor" href="#最小验证" aria-label="Permalink to &quot;最小验证&quot;">​</a></h2><p>第一次联调时，优先用最小请求证明四件事：</p><ol><li>地址写对了</li><li>Key 能鉴权</li><li>当前网络能打到网关</li><li>模型名是当前 Key 真能使用的那个</li></ol><p>先列模型：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://xiaolan1.cn/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;Authorization: Bearer sk-你的专属Key&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>如果能返回 JSON，说明地址、Key 和网络通常已经没有大问题。</p><p>再做一次最小对话测试：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#6F42C1;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> https://xiaolan1.cn/v1/chat/completions</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;Authorization: Bearer sk-你的专属Key&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &quot;Content-Type: application/json&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#005CC5;">  -d</span><span style="--shiki-light:#032F62;--shiki-dark:#032F62;"> &#39;{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">    &quot;model&quot;: &quot;从模型广场复制的模型名&quot;,</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">    &quot;messages&quot;: [</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">      { &quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;你好&quot; }</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">    ]</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#032F62;">  }&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>这一步成功后，再去接真正的客户端，会比一上来就把问题全堆在 GUI 工具里更容易排查。</p><h2 id="模型名来源" tabindex="-1">模型名来源 <a class="header-anchor" href="#模型名来源" aria-label="Permalink to &quot;模型名来源&quot;">​</a></h2><p>模型名以 <a href="https://xiaolan1.cn/pricing" target="_blank" rel="noreferrer">模型广场</a> 为准。</p><p>不要直接沿用官方平台示例里的模型名，也不要手敲一个自己觉得“差不多”的名字。<br> 小蓝中转站 会统一展示当前可用模型和价格，复制页面里的完整模型名更稳。</p><p>第一次接入时，建议先选一个轻量模型验证链路。<br> 能正常返回后，再切到长上下文、代码能力更强或更贵的模型。</p><h2 id="兼容但不等于完全相同" tabindex="-1">兼容但不等于完全相同 <a class="header-anchor" href="#兼容但不等于完全相同" aria-label="Permalink to &quot;兼容但不等于完全相同&quot;">​</a></h2><p>OpenAI 兼容接口解决的是请求格式问题。不同上游模型本身仍然可能有差异：</p><ul><li>上下文长度不同</li><li>是否支持图像输入不同</li><li>是否支持工具调用不同</li><li>是否支持流式输出不同</li><li>计费方式不同</li></ul><p>生产脚本上线前，先用目标模型跑一遍最小测试，再决定默认模型和超时策略。</p>`,52)])])}const k=a(l,[["render",p]]);export{u as __pageData,k as default};
